import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./resetpassword.css";

const ResetPassword = () => {
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const navigate = useNavigate();

  const handleResetPassword = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    const email = localStorage.getItem("resetEmail");  // Email stored in localStorage
    const otpToken = localStorage.getItem("otpToken"); // OTP stored after verification
    const newPassword = password.trim();

    console.log("Sending data to backend:", { email, password: newPassword, otpToken });

    if (!email || !otpToken) {
        setError("Session expired. Request a new OTP.");
        return;
    }

    if (!newPassword) {
        setError("Password is required.");
        return;
    }

    try {
        const response = await axios.post("http://localhost:5000/api/auth/reset-password", {
            email,
            password: newPassword,
            otpToken,
        });

        console.log("Response from server:", response.data);

        if (response.data.success) {
            setMessage("Password reset successful. Redirecting to login...");
            localStorage.removeItem("resetEmail");
            localStorage.removeItem("otpToken");
            setTimeout(() => navigate("/login"), 2000);
        } else {
            setError(response.data.message || "Error resetting password.");
        }
    } catch (err) {
        console.error("Error:", err.response ? err.response.data : err.message);
        setError(err.response?.data?.message || "Error resetting password. Please try again.");
    }
};

  return (
    <div className="reset-password-container">
      <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />
      <div className="reset-password-card">
        <h2>Reset Password</h2>
        <form onSubmit={handleResetPassword}>
          <input
            type="password"
            placeholder="Enter new password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
            disabled={isSubmitting}
          />
          <input
            type="password"
            placeholder="Confirm new password"
            value={confirmPassword}
            onChange={(e) => setConfirmPassword(e.target.value)}
            required
            disabled={isSubmitting}
          />
          <button type="submit" className="reset-password-button" disabled={isSubmitting}>
            {isSubmitting ? "Resetting..." : "Reset Password"}
          </button>
          {message && <p className="success-message">{message}</p>}
          {error && <p className="error-message">{error}</p>}
        </form>
      </div>
      <button onClick={() => navigate("/login")} className="back-button">Back to Login</button>
    </div>
  );
};

export default ResetPassword;
